import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;

class LifecycleTest {
    StringBuilder log = new StringBuilder();

    @BeforeEach
    void setup() { log.append("setup "); }

    @AfterEach
    void teardown() { log.append("teardown"); System.out.println(log); }

    @Test
    void testA() { log.append("A "); assertTrue(true); }

    @Test
    void testB() { log.append("B "); assertEquals(1, 1); }
}
